SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW view_rep_paid_tax (deposit_account_no, op_int, op_tax, working_day, seq_no) AS select tb.deposit_account_no , tb.op_int , tb.op_tax , tb.working_day ,  row_number() OVER () as seq_no
FROM (
  SELECT sc_dep_t_deposit_slip.account_no as deposit_account_no ,
         sc_dep_t_deposit_slip.op_receive_int as op_int ,           
         sc_dep_t_deposit_slip.op_tax as op_tax ,
         sc_dep_t_deposit_slip.working_day as working_day 
    FROM sc_dep_t_deposit_slip           
   WHERE 1=1 AND ( sc_dep_t_deposit_slip.op_tax > 0 ) AND ( sc_dep_t_deposit_slip.cancel_status = '0' )    

AND   sc_dep_t_deposit_slip.op_tax > 0   


union all


 SELECT sc_dep_m_interest_paid.deposit_account_no as deposit_account_no ,   
         sc_dep_m_interest_paid.interest_paid as op_int ,  
         sc_dep_m_interest_paid.tax_paid as op_tax , 
         sc_dep_m_interest_paid.working_day  as working_day 
    FROM sc_dep_m_interest_paid 
   WHERE 1=1 AND ( sc_dep_m_interest_paid.tax_paid > 0 )     

)  tb

/*WHERE*/

--and  tb.working_day = '14/1/2024'
 
ORDER BY tb.deposit_account_no ASC;

